resource "azurerm_function_app" "processor" {
  name                = "my-processor"
  # ... other config ...
  identity { type = "SystemAssigned" }
}

data "azurerm_key_vault" "secrets" {
  name                = "my-vault"
  resource_group_name = var.resource_group
}

data "azurerm_storage_account" "data" {
  name                = "mydatastorage"
  resource_group_name = var.resource_group
}

resource "azurerm_role_assignment" "kv_reader" {
  scope                = data.azurerm_key_vault.secrets.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_function_app.processor.identity[0].principal_id
}

resource "azurerm_role_assignment" "blob_contrib" {
  scope                = "${data.azurerm_storage_account.data.id}/blobServices/default/containers/output"
  role_definition_name = "Storage Blob Data Contributor"
  principal_id         = azurerm_function_app.processor.identity[0].principal_id
}

// Policy definition snippet — assign Key Vault Secrets User to any App Service
// that has a system-assigned managed identity
{
  "if": {
    "allOf": [
      { "field": "type", "equals": "Microsoft.Web/sites" },
      { "field": "identity.type", "contains": "SystemAssigned" }
    ]
  },
  "then": {
    "effect": "deployIfNotExists",
    "details": {
      "type": "Microsoft.Authorization/roleAssignments",
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/4633458b-17de-408a-b874-0445c86b69e6"
      ],
      "deployment": {
        "properties": {
          "mode": "incremental",
          "template": {
            "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
            "contentVersion": "1.0.0.0",
            "resources": [
              {
                "type": "Microsoft.Authorization/roleAssignments",
                "apiVersion": "2022-04-01",
                "name": "[guid(parameters('principalId'), parameters('roleDefinitionId'), parameters('scope'))]",
                "properties": {
                  "roleDefinitionId": "[parameters('roleDefinitionId')]",
                  "principalId": "[parameters('principalId')]",
                  "principalType": "ServicePrincipal"
                }
              }
            ]
          }
        }
      }
    }
  }
}
